const Nehemiah=(()=>{'use strict';const _base=(function(){const s=document.querySelector('script[src*="firm_foundation"]');if(!s)return'';const src=s.getAttribute('src');const idx=src.indexOf('Acts/');if(idx<0)return'';return src.substring(0,idx);})();const LOGIN_PAGE=_base+'Revelation/the_wall.min.html';const APP_PAGE=_base+'Revelation/the_good_shepherd.min.html';const ROLE_LEVELS={readonly:0,volunteer:1,care:2,leader:3,pastor:4,admin:5};const LOCAL_BYPASS_KEY='flock_local_bypass';function _isLocalEnv(){const h=location.hostname;return location.protocol==='file:'||h==='localhost'||h==='127.0.0.1';}
function _isLocalBypass(){return _isLocalEnv()&&localStorage.getItem(LOCAL_BYPASS_KEY)==='true';}
function _syntheticSession(){const allPerms={};const moduleKeys=['dashboard','daily-bread','upper-room','reading-plan','devotionals','prayer','my-requests','words','themes','sermons','songs','calendar','events','services','ministries','volunteers','todo','checkin','journal','directory','members','care','my-flock','prayer-admin','compassion','mirror','groups','attendance','giving','discipleship','outreach','learning','theology','library','comms','missions','statistics','reports','users','config','audit','interface-studio'];moduleKeys.forEach(k=>{allPerms[k]=true;});return{token:'local-bypass-'+Date.now(),email:'local@flockos.dev',role:'admin',roleLevel:5,displayName:'Local Developer',expiresAt:Date.now()+365*24*60*60*1000,permissions:allPerms,};}
function _ensureBypassSession(){const key='flock_auth_session';const existing=sessionStorage.getItem(key);if(!existing){sessionStorage.setItem(key,JSON.stringify(_syntheticSession()));}
const profKey='flock_auth_profile';if(!sessionStorage.getItem(profKey)){sessionStorage.setItem(profKey,JSON.stringify({email:'local@flockos.dev',displayName:'Local Developer',firstName:'Local',lastName:'Developer',role:'admin',theme:'Auto',}));}}
function enableLocalBypass(){if(!_isLocalEnv()){console.warn('[Nehemiah] Local Security Bypass is only available on file://, localhost, or 127.0.0.1.');return;}
localStorage.setItem(LOCAL_BYPASS_KEY,'true');_ensureBypassSession();console.log('%c[Nehemiah] Local Security Bypass ENABLED — admin session injected.','color:#e8a838;font-weight:bold');}
function disableLocalBypass(){localStorage.removeItem(LOCAL_BYPASS_KEY);try{const raw=sessionStorage.getItem('flock_auth_session');if(raw){const s=JSON.parse(raw);if(s.email==='local@flockos.dev'){sessionStorage.removeItem('flock_auth_session');sessionStorage.removeItem('flock_auth_profile');}}}catch(_){}
console.log('%c[Nehemiah] Local Security Bypass DISABLED.','color:#e8a838;font-weight:bold');}
if(_isLocalBypass()){_ensureBypassSession();}
function isAuthenticated(){if(_isLocalBypass())return true;return TheVine.session()!==null;}
function getSession(){if(_isLocalBypass()){_ensureBypassSession();}
return TheVine.session();}
function getProfile(){try{const raw=sessionStorage.getItem('flock_auth_profile');return raw?JSON.parse(raw):null;}catch(_){return null;}}
function guard(){if(_isLocalBypass()){_ensureBypassSession();}
const session=getSession();if(!session){window.location.replace(LOGIN_PAGE);return null;}
return session;}
function guardLogin(){if(_isLocalBypass()){window.location.replace(APP_PAGE);return;}
if(isAuthenticated()){window.location.replace(APP_PAGE);}}
function hasRole(minRole){const session=getSession();if(!session||!session.role)return false;const userLevel=ROLE_LEVELS[session.role]??-1;const reqLevel=ROLE_LEVELS[minRole]??99;return userLevel>=reqLevel;}
function canAccess(moduleKey){const session=getSession();if(!session)return false;if(session.permissions&&typeof session.permissions==='object'){return session.permissions[moduleKey]===true;}
return true;}
function requireRole(minRole){if(!hasRole(minRole)){throw new Error('Access denied. Requires '+minRole+' or higher.');}}
async function login(email,passcode){if(!email||!passcode){throw new Error('Email and passcode are required.');}
const result=await TheVine.john.auth.login({email,passcode});if(!result||!result.ok){throw new Error((result&&result.error)||'Login failed.');}
if(result.profile){try{sessionStorage.setItem('flock_auth_profile',JSON.stringify(result.profile));}catch(_){}}
return result.session||result;}
async function logout(){try{await TheVine.john.auth.logout({});}catch(_){}
window.location.replace(LOGIN_PAGE);}
async function register(opts){if(!opts.email||!opts.passcode||!opts.firstName){throw new Error('Email, passcode, and first name are required.');}
const result=await TheVine.john.auth.register(opts);if(!result||!result.ok){throw new Error((result&&result.error)||'Registration failed.');}
return result;}
async function forgotPassword(email){if(!email)throw new Error('Email is required.');const result=await TheVine.john.auth.forgotPassword({email});if(!result||!result.ok){throw new Error((result&&result.error)||'Request failed.');}
return result;}
async function resetWithCode(email,resetCode,newPasscode){if(!email||!resetCode||!newPasscode){throw new Error('Email, reset code, and new passcode are required.');}
const result=await TheVine.john.auth.resetWithToken({email,resetCode,newPasscode});if(!result||!result.ok){throw new Error((result&&result.error)||'Reset failed.');}
return result;}
async function setupVault(pin){if(typeof TheWellspring==='undefined'||!TheWellspring.vault){throw new Error('Offline vault not available');}
var s=getSession();if(!s)throw new Error('Must be logged in to set up offline vault');await TheWellspring.vault.setup(pin,{email:s.email,role:s.role,roleLevel:s.roleLevel,displayName:s.displayName,permissions:s.permissions||{},isSeed:s.isSeed||false,});}
async function loginOffline(pin){if(typeof TheWellspring==='undefined'||!TheWellspring.vault){throw new Error('Offline vault not available');}
var session=await TheWellspring.vault.unlock(pin);session.expiresAt=Date.now()+(4*60*60*1000);session.token='offline-'+Date.now();sessionStorage.setItem('flock_auth_session',JSON.stringify(session));return session;}
async function hasVault(){if(typeof TheWellspring==='undefined'||!TheWellspring.vault)return false;return TheWellspring.vault.exists();}
async function destroyVault(){if(typeof TheWellspring==='undefined'||!TheWellspring.vault)return;return TheWellspring.vault.destroy();}
return Object.freeze({isAuthenticated,guard,guardLogin,getSession,getProfile,hasRole,canAccess,requireRole,login,logout,register,forgotPassword,resetWithCode,setupVault,loginOffline,hasVault,destroyVault,enableLocalBypass,disableLocalBypass,isLocalBypass:_isLocalBypass,});})();